import React from "react";
import { NavLink } from "react-router-dom";
import "./DashboardSidebar.css";
import { isAdmin } from "./auth";   // ← FIXED

const DashboardSidebar = () => {
  return (
    <div className="sidebar">
      <h2>Dashboard</h2>

      <NavLink to="/dashboard/employee-details">
        Employees
      </NavLink>

      {isAdmin() && (
        <NavLink to="/dashboard/employee-details/leaves">
          Leave Requests
        </NavLink>
      )}

      <NavLink to="/dashboard/timesheet">Timesheet</NavLink>
      <NavLink to="/dashboard/calendar">Calendar</NavLink>
    </div>
  );
};

export default DashboardSidebar;
